// static/js/map.js

// This file handles additional map interactions
// The main map is generated by Folium (Python)

console.log('🗺️ Map JS loaded');

// Function to analyze area (called from index.html)
async function analyzeArea(lat, lon) {
    try {
        const response = await fetch(`/api/area-details?lat=${lat}&lon=${lon}`);
        const data = await response.json();
        
        console.log('Area analysis:', data);
        return data;
    } catch (error) {
        console.error('Error analyzing area:', error);
    }
}

// Load initial stats
async function loadStats() {
    try {
        const response = await fetch('/api/map-data');
        const data = await response.json();
        
        document.getElementById('total-parks').textContent = data.stats.total_parks;
        document.getElementById('total-ev').textContent = data.stats.total_ev_stations;
        document.getElementById('avg-aqi').textContent = data.stats.avg_aqi;
        
        console.log('Stats loaded:', data.stats);
    } catch (error) {
        console.error('Error loading stats:', error);
    }
}

// Initialize
document.addEventListener('DOMContentLoaded', loadStats);